element.calculation:
(function calculatedFieldValue(current) {
    // 1. Get the values from the current record
    // REPLACE these string values with your actual backend field names
    var degreeLevel = current.getValue('u_degree_level'); 
    var obtained = parseFloat(current.getValue('u_obtained_marks')) || 0;
    var total = parseFloat(current.getValue('u_total_marks')) || 0;
    var cgpa = parseFloat(current.getValue('u_cgpa')) || 0;

    var finalPercentage = 0.0;

    // 2. Determine the calculation logic based on the degree
    if (degreeLevel == "Bachelor's" || degreeLevel == "Master's") {
        // Calculate based on CGPA
        if (cgpa > 0 && cgpa <= 4.0) {
            finalPercentage = (cgpa / 4.0) * 100;
        }
    } else {
        // Calculate based on standard marks
        if (total > 0) {
            finalPercentage = (obtained / total) * 100;
        }
    }

    // 3. Return the value formatted to 2 decimal places
    return parseFloat(finalPercentage.toFixed(2));

})(current);
